mapper.select:
select
  (
    select count(1)
    from payment_order po
    where po.tenant_id = #{tenantId}
      and po.cashier_config_id = #{cashierConfigId}
  )
  + (
    select count(1)
    from payment_virtual_channel_payment sp
    where sp.tenant_id = #{tenantId}
      and sp.cashier_config_id = #{cashierConfigId}
  )
